-- Hyprland config (lua) - migrated from hyprlang on 2026-05-11.
-- Hyprland >= 0.55 prefers ~/.config/hypr/hyprland.lua over hyprland.conf.
-- Reference: https://wiki.hypr.land/Configuring/Start/

----------------------------------------------------------------------
-- MONITORS
----------------------------------------------------------------------
-- Generated by nwg-displays on 2025-12-22; mirror that layout here.
hl.monitor({
    output   = "DP-1",
    mode     = "2560x1440@180.0",
    position = "0x1440",
    scale    = 1.0,
})
hl.monitor({
    output    = "HDMI-A-1",
    mode      = "1920x1080@74.97",
    position  = "2560x1160",
    scale     = 1.0,
    transform = 3,
})

----------------------------------------------------------------------
-- ENVIRONMENT
----------------------------------------------------------------------
hl.env("WLR_NO_HARDWARE_CURSORS",       "1")
hl.env("WLR_RENDERER_ALLOW_SOFTWARE",   "1")
hl.env("XCURSOR_SIZE",                  "24")
hl.env("WLR_DRM_NO_ATOMIC",             "1")
hl.env("QT_QPA_PLATFORM",               "wayland")
hl.env("ELECTRON_OZONE_PLATFORM_HINT",  "auto")
hl.env("QT_QPA_PLATFORMTHEME",          "gtk3")
hl.env("QT_QPA_PLATFORMTHEME_QT6",      "gtk3")
hl.env("TERMINAL",                      "kitty")

-- Cursor (was dms/cursor.conf, auto-generated by DMS in hyprlang format).
-- Inlined here because lua configs do not source .conf files.
hl.env("HYPRCURSOR_THEME", "phinger-cursors-dark")
hl.env("XCURSOR_THEME",    "phinger-cursors-dark")
hl.env("HYPRCURSOR_SIZE",  "24")
hl.env("XCURSOR_SIZE",     "24")

----------------------------------------------------------------------
-- AUTOSTART
----------------------------------------------------------------------
hl.on("hyprland.start", function()
    hl.exec_cmd("/usr/lib/polkit-gnome/polkit-gnome-authentication-agent-1")
    hl.exec_cmd("wl-paste --watch cliphist store")
    hl.exec_cmd("dms run")
    hl.exec_cmd("hyprctl setcursor phinger-cursors-dark 24")
    hl.exec_cmd("hyprpm reload -n")
    hl.exec_cmd("1password --silent")
    hl.exec_cmd(os.getenv("HOME") .. "/dotfiles/arch/scripts/restart_bluetooth")
    hl.exec_cmd("protonmail-bridge --no-window")
    hl.exec_cmd("protonvpn-app --start-minimized")
    -- Watch DMS-generated dms/*.conf and re-apply via lua at runtime.
    hl.exec_cmd(os.getenv("HOME") .. "/dotfiles/arch/scripts/dms-hypr-watcher.sh")
end)

----------------------------------------------------------------------
-- LOOK AND FEEL
----------------------------------------------------------------------
hl.config({
